// Récupérer tous les fichiers de la réponse
const response = $input.first().json;
const allItems = response.files || [];

// Séparer dossiers et fichiers
const folders = new Map();
const files = [];

for (const item of allItems) {
  const entry = {
    id: item.id,
    name: item.name,
    mimeType: item.mimeType,
    parentId: item.parents && item.parents.length > 0 ? item.parents[0] : 'root'
  };

  if (item.mimeType === 'application/vnd.google-apps.folder') {
    folders.set(item.id, {
      ...entry,
      type: 'dossier',
      sousDossiers: [],
      fichiers: []
    });
  } else {
    files.push({
      ...entry,
      type: 'fichier'
    });
  }
}

// Associer les fichiers à leurs dossiers parents
for (const file of files) {
  const parentFolder = folders.get(file.parentId);
  if (parentFolder) {
    parentFolder.fichiers.push({
      id: file.id,
      nom: file.name,
      type: 'fichier',
      mimeType: file.mimeType
    });
  }
}

// Associer les sous-dossiers à leurs parents
for (const [folderId, folder] of folders) {
  const parentFolder = folders.get(folder.parentId);
  if (parentFolder) {
    parentFolder.sousDossiers.push(folderId);
  }
}

// Fonction récursive pour construire l'arbre
function buildFolderTree(folderId) {
  const folder = folders.get(folderId);
  if (!folder) return null;

  const result = {
    id: folder.id,
    nom: folder.name,
    type: 'dossier',
    sousDossiers: [],
    fichiers: folder.fichiers
  };

  for (const subFolderId of folder.sousDossiers) {
    const subTree = buildFolderTree(subFolderId);
    if (subTree) {
      result.sousDossiers.push(subTree);
    }
  }

  return result;
}

// Trouver les dossiers racine (ceux dont le parent n'est pas dans notre liste)
const rootFolders = [];
const rootFiles = [];

for (const [folderId, folder] of folders) {
  if (!folders.has(folder.parentId)) {
    rootFolders.push(folderId);
  }
}

for (const file of files) {
  if (!folders.has(file.parentId)) {
    rootFiles.push({
      id: file.id,
      nom: file.name,
      type: 'fichier',
      mimeType: file.mimeType
    });
  }
}

// Construire la structure finale
const structure = {
  dossiers: rootFolders.map(id => buildFolderTree(id)).filter(Boolean),
  fichiers: rootFiles
};

// Statistiques
let totalSousDossiers = 0;
let totalFichiers = files.length;

function countItems(node) {
  if (!node) return;
  totalSousDossiers++;
  for (const sub of node.sousDossiers || []) {
    countItems(sub);
  }
}

structure.dossiers.forEach(countItems);

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    statistiques: {
      totalDossiers: folders.size,
      totalFichiers: totalFichiers,
      dossiersRacine: rootFolders.length,
      fichiersRacine: rootFiles.length
    },
    arborescence: structure
  }
}];
